class Solution {
public:
    bool reorderedPowerOf2(int n) {
        string str = to_string(n);
        sort(str.begin(), str.end());
        for (int i = 0; i < 32; i++) {
            string powerOf2 = to_string(1 << i);
            sort(powerOf2.begin(), powerOf2.end());
            if (str == powerOf2) return true;
        }
        return false;
    }
};
